import{bQ as e,aL as o,u as t,G as i}from"./chunks/framework.jc7iVf2j.js";const d=JSON.parse('{"title":"CLAUDE.md","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://knotens.org/CLAUDE"}]]},"headers":[],"relativePath":"CLAUDE.md","filePath":"CLAUDE.md","lastUpdated":1778926451000}');const a=e({name:"CLAUDE.md"},[["render",function(e,d,a,s,c,r){return o(),t("div",null,[...d[0]||(d[0]=[i('<h1 id="claude-md" tabindex="-1">CLAUDE.md <a class="header-anchor" href="#claude-md" aria-label="Permalink to &quot;CLAUDE.md&quot;">​</a></h1><p>This file provides guidance to Claude Code (claude.ai/code) when working with code in this repository.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Personal blog &quot;京华&quot; (knotens.org) built on <strong>VitePress</strong> with a fully custom theme — a personalized instance of <code>vitepress-theme-curve</code> (by imsyy). Site content is in Chinese. <code>README.md</code> is the upstream theme&#39;s documentation, not project-specific docs.</p><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><p>Uses <strong>pnpm</strong> (v9.15.4, Node &gt;=20). <code>.npmrc</code> sets <code>shamefully-hoist=true</code>.</p><ul><li><code>pnpm dev</code> — dev server at <a href="http://127.0.0.1:9877" target="_blank" rel="noreferrer">http://127.0.0.1:9877</a></li><li><code>pnpm build</code> — <code>vitepress build</code>, outputs to <code>.vitepress/dist</code></li><li><code>pnpm preview</code> — serve the built site</li><li><code>pnpm lint</code> — ESLint (airbnb-base + vue3) with <code>--fix</code></li><li><code>pnpm format</code> — Prettier write across the repo</li><li><code>pnpm up</code> — shortcut for <code>git add . &amp;&amp; git commit -m &quot;update blog&quot; &amp;&amp; git push</code></li></ul><p>No test suite is configured.</p><h2 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to &quot;Deployment&quot;">​</a></h2><p>Pushing to <code>master</code> triggers <code>.github/workflows/</code> → builds and publishes <code>.vitepress/dist</code> to the <code>pages</code> branch (GitHub Pages). <code>vercel.json</code> also configures a Vercel deployment (SPA-style rewrites, output <code>.vitepress/dist</code>).</p><h2 id="theme-configuration-—-two-file-pattern" tabindex="-1">Theme configuration — two-file pattern <a class="header-anchor" href="#theme-configuration-—-two-file-pattern" aria-label="Permalink to &quot;Theme configuration — two-file pattern&quot;">​</a></h2><p>Site customization lives in the <strong>root <code>themeConfig.mjs</code></strong> (site title, nav, footer, comment system, search, etc.). <code>.vitepress/init.mjs</code> <code>Object.assign</code>-merges it <em>over</em> the default config at <code>.vitepress/theme/assets/themeConfig.mjs</code>.</p><ul><li>Edit the <strong>root <code>themeConfig.mjs</code></strong> for all site settings.</li><li>Never rename or delete <code>.vitepress/theme/assets/themeConfig.mjs</code> — it is the fallback the merge starts from (<code>.gitignore</code> explicitly un-ignores it).</li><li>The merge is shallow: overriding a nested object in the root file replaces that whole object.</li></ul><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p><strong>Build-time data layer.</strong> <code>.vitepress/config.mjs</code> calls <code>getAllPosts()</code> (<code>theme/utils/getPostData.mjs</code>), which globs <code>posts/**.md</code>, parses frontmatter with <code>gray-matter</code>, and derives tags/categories/archives. This data is injected into <code>themeConfig.postData / tagsData / categoriesData / archivesData</code> and consumed across the theme. RSS is generated in the <code>buildEnd</code> hook.</p><p><strong>Custom theme</strong> — <code>.vitepress/theme/</code> is a complete custom theme:</p><ul><li><code>index.mjs</code> — registers Pinia (with <code>pinia-plugin-persistedstate</code>), vue-instantsearch, and route guards.</li><li><code>App.vue</code> — root layout. Page type is chosen by route, not router config: <code>/posts/</code> in the path → <code>Post</code> view; <code>frontmatter.layout === &#39;home&#39;</code> → <code>Home</code>; otherwise → <code>Page</code>.</li><li><code>components/</code> and <code>views/</code> are <strong>auto-imported</strong> (unplugin-vue-components); Vue + VitePress APIs are auto-imported too — no explicit <code>import</code> needed in <code>.vue</code> files.</li><li><code>store/index.js</code> — single Pinia store (<code>mainStore</code>) for UI state (theme, player, scroll, menus).</li><li>Path alias <code>@</code> → <code>.vitepress/theme</code>.</li></ul><h2 id="content-model" tabindex="-1">Content model <a class="header-anchor" href="#content-model" aria-label="Permalink to &quot;Content model&quot;">​</a></h2><ul><li><strong><code>posts/</code></strong> — blog articles. <strong>File path = URL path.</strong> Frontmatter fields read by the data layer: <code>title, date, categories, tags, description, top, cover</code> (plus <code>copyright, references</code> used by the post view). <code>top: true</code> pins an article; posts sort by <code>top</code> then <code>date</code> descending.</li><li><strong><code>pages/</code></strong> — site pages; each <code>.md</code> mounts a view component (e.g. <code>pages/about.md</code> → <code>views/About.vue</code>).</li><li><strong>Dynamic routes</strong> use VitePress <code>[param].paths.mjs</code> files, all driven by post data: <code>page/[num].md</code> (home pagination, <code>postSize</code> posts per page), <code>pages/categories/[name].md</code>, <code>pages/tags/[name].md</code>.</li><li><strong><code>public/</code></strong> — static assets served at root (<code>images/</code>, <code>fonts/</code>, <code>favicon.ico</code>, <code>robots.txt</code>).</li></ul><h2 id="markdown-extensions" tabindex="-1">Markdown extensions <a class="header-anchor" href="#markdown-extensions" aria-label="Permalink to &quot;Markdown extensions&quot;">​</a></h2><p><code>theme/utils/markdownConfig.mjs</code> adds, beyond VitePress defaults:</p><ul><li>Custom containers: <code>:::timeline</code>, <code>:::radio</code>, <code>:::button</code>, <code>:::card</code></li><li>Obsidian-style admonitions via fenced code blocks: <code>```ad-note</code>, <code>ad-warning</code>, <code>ad-tip</code>, <code>ad-danger</code>, etc.</li><li><code>markdown-it-attrs</code>, tabs plugin, math (MathJax3), line numbers, TOC levels 1–3</li><li>Images are wrapped for the Fancybox lightbox (toggle via <code>fancybox.enable</code>)</li></ul><h2 id="conventions-gotchas" tabindex="-1">Conventions / gotchas <a class="header-anchor" href="#conventions-gotchas" aria-label="Permalink to &quot;Conventions / gotchas&quot;">​</a></h2><ul><li>ESLint and Prettier both enforce <strong>double quotes</strong>; Prettier: 2-space indent, semicolons, <code>printWidth</code> 100, <code>trailingComma: all</code>.</li><li><code>ignoreDeadLinks: true</code> — broken links will not fail the build.</li><li>Production builds strip <code>console.log</code> (terser <code>pure_funcs</code>).</li><li><code>srcExclude</code> keeps <code>README.md</code> and <code>TODO.md</code> from being built as pages.</li><li>External links are rewritten through a redirect interstitial (<code>jumpRedirect</code>, <code>public/redirect.html</code>); <code>cleanUrls</code> is on.</li></ul>',24)])])}]]);export{d as __pageData,a as default};
